// DFA: M = (Q, Σ, δ, q0, F)
function simulateDFA(M, input):
 currentState = q0
 for each symbol a in input:
 if δ(currentState, a) is defined:
 currentState = δ(currentState, a)
 else:
 return REJECT
 if currentState in F:
 return ACCEPT
 else:
 return REJECT

