// Subset Construction Algorithm
function nfaToDfa(NFA):
 DFAstates = empty set of states
 DFAtransitions = empty set
 queue = empty queue

 // Start: ε-closure of NFA start state
 startState = epsilonClosure({nfaStart})
 add startState to DFAstates
 enqueue startState

 while queue not empty:
 S = dequeue()
 for each input symbol a in alphabet:
 // Compute move(S, a) then ε-closure
 T = epsilonClosure(move(S, a))
 if T not in DFAstates:
 add T to DFAstates
 enqueue T
 add transition S --a--> T to DFAtransitions

 return DFA with accepting states = states containing NFA accepting states

// ε-closure: All states reachable via ε-transitions
function epsilonClosure(S):
 result = S
 stack = S
 while stack not empty:
 state = pop(stack)
 for each t in epsilonTransitions(state):
 if t not in result:
 add t to result
 push t to stack
 return result

