// TM for language L = {ww^R | w ∈ {0,1}*}
// Uses matching from outside to center

function TM-PALINDROME(input):
 currentState = q0
 tape = input + 'BB...' (blank padding)
 head = 0 // Start at leftmost

 while true:
 switch(currentState):
 case q0: // Find rightmost non-blank
 if tape[head] == 'B':
 // Reached end, go to center
 head = head + 1
 currentState = q1
 else:
 head = head + 1
 break

 case q1: // Match from ends
 if tape[head] == 'B':
 // Reached center (odd) or crossed (even)
 currentState = q_accept
 else:
 // Mark current, find right end
 symbol = tape[head]
 tape[head] = 'X' // Mark as visited
 currentState = q2
 head = head + 1
 break

 case q2: // Move right to find end
 if tape[head] != 'B':
 head = head + 1
 else:
 // Found end, check match
 if tape[head-1] == symbol:
 tape[head] = 'X'
 head = head - 1
 currentState = q3
 else:
 currentState = q_reject
 break

 case q3: // Move left to find next unmarked
 if tape[head] == 'X' or tape[head] == 'B':
 head = head - 1
 else:
 currentState = q1
 break

 case q_accept:
 return ACCEPT

 case q_reject:
 return REJECT

