// Reduction from 3-SAT to CLIQUE
// 3-SAT: Boolean formula in CNF with 3 literals per clause
// CLIQUE: Find a clique of size k in a graph

function reduce3SATtoClique(formula):
 // Create graph G
 vertices = empty
 edges = empty

 // For each clause, create 3 vertices (one per literal)
 clause_id = 0
 for each clause (l1 ∨ l2 ∨ l3) in formula:
 for each literal li in clause:
 add vertex v(clause_id, li)
 clause_id = clause_id + 1

 // Add edges between vertices except:
 // 1. Vertices in same clause (can't pick two from one clause)
 // 2. Contradictory literals (x and ¬x)
 for each pair of vertices (u, v):
 if u.clause != v.clause:
 if not isNegation(u.literal, v.literal):
 add edge (u, v)

 // Set k = number of clauses
 k = number_of_clauses

 // Return (G, k)
 // If G has clique of size k, formula is satisfiable
 // If formula is satisfiable, G has clique of size k
 return (G, k)

// Correctness: Each clause contributes one literal to clique
// Edge constraints ensure no conflict (same clause or negation)
// Time: O(m²) where m = number of literals = 3n (n clauses)
// Polynomial time reduction!
